interrupt.pattern_node:
def approve(state) -> dict:
    if state['run_mode'] == 'automated':
        return {'approved': state['recommended']}
    human = interrupt({'question': 'Approve?', 'recommended': state['recommended']})
    return {'approved': human if human is not None else state['recommended']}
